	fmt.Fprintf(&builder, "<tr><td>Subject</td><td>%s</td></tr>\n", escapeHTML(subject))
	fmt.Fprintf(&builder, "<tr><td>Feedback Content</td><td>%s</td></tr>\n", escapeHTML(feedbackContent))
