package main

import (
	"fmt"
	"net/mail"
	"strings"
)

// BuildFeedbackEmail constructs an HTML-formatted email body for user feedback
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Validate email addresses
	if _, err := mail.ParseAddress(fromAddr); err != nil {
		return "", err
	}
	if _, err := mail.ParseAddress(toAddr); err != nil {
		return "", err
	}

	// Create the email body using HTML formatting
	var builder strings.Builder

	// Write the HTML content with proper content type header
	builder.WriteString("Content-Type: text/html; charset=UTF-8\n")
	fmt.Fprintf(&builder, "From: %s\n", fromAddr)
	fmt.Fprintf(&builder, "To: %s\n", toAddr)
	fmt.Fprintf(&builder, "Subject: %s\n\n", subject)
	fmt.Fprintf(&builder, "<html><body>\n")
	fmt.Fprintf(&builder, "<h2>User Feedback</h2>\n")
	fmt.Fprintf(&builder, "<table border='1' cellpadding='5' cellspacing='0'>\n")
	fmt.Fprintf(&builder, "<tr><th>Field</th><th>Value</th></tr>\n")
	fmt.Fprintf(&builder, "<tr><td>Username</td><td>%s</td></tr>\n", escapeHTML(userName))
	fmt.Fprintf(&builder, "<tr><td>Subject</td><td>%s</td></tr>\n", escapeHTML(subject))
	fmt.Fprintf(&builder, "<tr><td>Feedback Content</td><td>%s</td></tr>\n", escapeHTML(feedbackContent))
	fmt.Fprintf(&builder, "</table>\n")
	fmt.Fprintf(&builder, "</body></html>")

	return builder.String(), nil
}

// escapeHTML escapes special HTML characters to prevent HTML injection
func escapeHTML(s string) string {
	s = strings.ReplaceAll(s, "&", "&amp;")
	s = strings.ReplaceAll(s, "<", "&lt;")
	s = strings.ReplaceAll(s, ">", "&gt;")
	s = strings.ReplaceAll(s, "\"", "&quot;")
	s = strings.ReplaceAll(s, "'", "&#39;")
	return s
}

func main() {
	// Example usage
	email, err := BuildFeedbackEmail(
		"user@example.com",
		"support@company.com",
		"John Doe",
		"Feature Request",
		"I would like to see a dark mode option in the application.",
	)

	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}

	fmt.Println(email)
}

